import React, { useEffect, useState } from "react";
import axios from "axios";
import Table from "../Components/Table";

const Report = () => {
  const [monthlyRevenue, setMonthlyRevenue] = useState([]);
  const [yearlyRevenue, setYearlyRevenue] = useState([]);
  const [topCustomers, setTopCustomers] = useState([]);
  const [roomUsage, setRoomUsage] = useState([]);
  const [viewMode, setViewMode] = useState("monthly");

  const apiBase = "http://localhost:5000/api/report";

  useEffect(() => {
    fetchRevenue();
    fetchTopCustomers();
    fetchRoomUsage();
  }, []);

  const fetchRevenue = async () => {
    try {
      const res = await axios.get(`${apiBase}/revenue`);
      setMonthlyRevenue(res.data.monthly || []);
      setYearlyRevenue(res.data.yearly || []);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải báo cáo doanh thu");
    }
  };

  const fetchTopCustomers = async () => {
    try {
      const res = await axios.get(`${apiBase}/topcustomer`);
      setTopCustomers(res.data || []);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải top khách hàng");
    }
  };

  const fetchRoomUsage = async () => {
    try {
      const res = await axios.get(`${apiBase}/roomusage`);
      setRoomUsage(res.data || []);
    } catch (err) {
      console.error(err);
      alert("Lỗi khi tải công suất phòng");
    }
  };

  const Card = ({ title, children }) => (
    <div className="border rounded-xl shadow-md p-6 mb-8 bg-white">
      <h2 className="text-lg font-semibold mb-3">{title}</h2>
      {children}
    </div>
  );

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <h1 className="text-2xl font-bold mb-8 text-center">Báo cáo tổng hợp</h1>

      {/* Doanh thu */}
      <Card title="Doanh thu">
        <div className="mb-4 flex items-center gap-2">
          <label className="font-semibold">Xem theo:</label>
          <select
            value={viewMode}
            onChange={(e) => setViewMode(e.target.value)}
            className="border rounded px-2 py-1"
          >
            <option value="monthly">Tháng</option>
            <option value="yearly">Năm</option>
          </select>
        </div>

        {viewMode === "monthly" ? (
          <Table
            columns={[
              { key: "Nam", label: "Năm" },
              { key: "Thang", label: "Tháng" },
              { key: "DoanhThu", label: "Doanh thu" },
            ]}
            data={monthlyRevenue}
          />
        ) : (
          <Table
            columns={[
              { key: "Nam", label: "Năm" },
              { key: "DoanhThu", label: "Doanh thu" },
            ]}
            data={yearlyRevenue}
          />
        )}
      </Card>

      {/* Top khách hàng */}
      <Card title="Top khách hàng">
        <Table
          columns={[
            { key: "MaKH", label: "Mã KH" },
            { key: "HoTen", label: "Họ tên" },
            { key: "SoLanDat", label: "Số lần đặt" },
            { key: "TongChiTieu", label: "Tổng chi tiêu" },
          ]}
          data={topCustomers}
        />
      </Card>

      {/* Công suất phòng */}
      <Card title="Công suất phòng">
        <Table
          columns={[
            { key: "PhongSo", label: "Phòng số" },
            { key: "SoLanThue", label: "Số lần thuê" },
          ]}
          data={roomUsage}
        />
      </Card>
    </div>
  );
};

export default Report;
